SELECT t.ticket_no AS ticketNo, t.issue_type AS issueType, t.status AS status, t.title AS title, t.order_id AS orderId, o.order_no AS orderNo, o.status AS orderStatus, COALESCE(o.pay_amount, 0) AS payAmount, COALESCE(o.currency, 'USD') AS payCurrency, COALESCE(oi.cover_image_url, '') AS orderCover, t.shipment_id AS shipmentId, s.status AS shipmentStatus, COALESCE(lsn.note, '') AS shipmentStatusLogSnapshot, t.assigned_to_user_id AS assignedToUserId, t.last_message_at AS lastMessageAt, t.created_at AS createdAt, t.updated_at AS updatedAt FROM cs_ticket t LEFT JOIN orders o ON o.id = t.order_id LEFT JOIN shipment s ON s.id = t.shipment_id LEFT JOIN order_item oi ON oi.id = (SELECT oi_min.id FROM order_item oi_min WHERE oi_min.order_id = t.order_id ORDER BY oi_min.id LIMIT 1) LEFT JOIN shipment_status_log lsn ON lsn.id = (SELECT l.id FROM shipment_status_log l WHERE l.shipment_id = t.shipment_id ORDER BY COALESCE(l.event_time, l.created_at) DESC, l.id DESC LIMIT 1)
t.user_id = #{userId}
AND t.status = #{status}
AND t.issue_type = #{issueType}
AND o.order_no = #{orderNo}
AND s.shipment_no = #{shipmentNo}
AND t.created_at >= #{createdFrom}
AND t.created_at <= #{createdTo}
ORDER BY t.created_at DESC, t.id DESC LIMIT #{limit} OFFSET #{offset}

