        AND t.created_at  >=  #{createdFrom}


        AND t.created_at  <=  #{createdTo}

SELECT t.id AS ticketId, t.ticket_no AS ticketNo, t.user_id AS userId, t.issue_type AS issueType, t.status AS status, t.priority AS priority, t.channel AS channel, t.title AS title, t.order_id AS orderId, t.order_item_id AS orderItemId, o.order_no AS orderNo, o.status AS orderStatus, COALESCE(o.pay_amount, 0) AS payAmount, COALESCE(o.currency, 'USD') AS payCurrency, COALESCE(oi.cover_image_url, '') AS orderCover, t.shipment_id AS shipmentId, s.status AS shipmentStatus, COALESCE(lsn.note, '') AS shipmentStatusLogSnapshot, t.assigned_to_user_id AS assignedToUserId, t.assigned_at AS assignedAt, t.last_message_at AS lastMessageAt, t.sla_due_at AS slaDueAt, t.created_at AS createdAt, t.updated_at AS updatedAt FROM cs_ticket t LEFT JOIN orders o ON o.id = t.order_id LEFT JOIN shipment s ON s.id = t.shipment_id LEFT JOIN order_item oi ON oi.id = (SELECT oi_min.id FROM order_item oi_min WHERE oi_min.order_id = t.order_id ORDER BY oi_min.id LIMIT 1) LEFT JOIN shipment_status_log lsn ON lsn.id = (SELECT l.id FROM shipment_status_log l WHERE l.shipment_id = t.shipment_id ORDER BY COALESCE(l.event_time, l.created_at) DESC, l.id DESC LIMIT 1)
AND t.ticket_no = #{ticketNo}
AND t.user_id = #{userId}
AND t.order_id = #{orderId}
AND t.shipment_id = #{shipmentId}
AND t.issue_type = #{issueType}
AND t.status = #{status}
AND t.priority = #{priority}
AND t.assigned_to_user_id = #{assignedToUserId}
AND t.claim_external_id = #{claimExternalId}
AND t.sla_due_at >= #{slaDueFrom}
AND t.sla_due_at <= #{slaDueTo}
AND t.created_at >= #{createdFrom}
AND t.created_at <= #{createdTo}
ORDER BY FIELD(t.priority, 'URGENT', 'HIGH', 'NORMAL', 'LOW'), t.created_at DESC, t.id DESC LIMIT #{limit} OFFSET #{offset}

