SELECT t.*
FROM cs_ticket t FORCE INDEX (idx_ticket_status_update)
WHERE t.status = #{status}
  AND t.updated_at  <=  #{updatedBefore}
ORDER BY t.updated_at, t.id
LIMIT #{limit}

