UPDATE cs_ticket
SET status            = #{toStatus},
    resolved_at       = #{resolvedAt},
    closed_at         = #{closedAt},
    updated_at        = #{updatedAt}
WHERE id = #{ticketId}
  AND user_id = #{userId}
  AND status = #{expectedFromStatus}
LIMIT 1
